import React from "react";
import { Container, Nav, Navbar } from "react-bootstrap";
import { NavLink, Outlet, useNavigate } from "react-router-dom";

import { authApi } from "../utils/api";

function Layout({ user, setUser }) {
  const navigate = useNavigate();

  const handleLogout = async () => {
    await authApi.logout();
    setUser(null);
    navigate("/login");
  };

  return (
    <div className="app-shell">
      <Navbar bg="dark" variant="dark" expand="lg" className="shadow-sm">
        <Container fluid>
          <Navbar.Brand>Sales CRM</Navbar.Brand>
          <Navbar.Toggle aria-controls="main-nav" />
          <Navbar.Collapse id="main-nav">
            <Nav className="me-auto">
              <Nav.Link as={NavLink} to="/">Dashboard</Nav.Link>
              <Nav.Link as={NavLink} to="/customers">Customers</Nav.Link>
              <Nav.Link as={NavLink} to="/enquiries">Enquiries</Nav.Link>
              <Nav.Link as={NavLink} to="/quotations">Quotations</Nav.Link>
              <Nav.Link as={NavLink} to="/orders">Sales Orders</Nav.Link>
              <Nav.Link as={NavLink} to="/invoices">Invoices</Nav.Link>
              <Nav.Link as={NavLink} to="/reports">Reports</Nav.Link>
              <Nav.Link as={NavLink} to="/process-monitor">Process Monitor</Nav.Link>
            </Nav>
            <div className="d-flex align-items-center gap-3 text-white">
              <span>{user?.username}</span>
              <button type="button" className="btn btn-outline-light btn-sm" onClick={handleLogout}>
                Logout
              </button>
            </div>
          </Navbar.Collapse>
        </Container>
      </Navbar>
      <Container fluid className="py-4">
        <Outlet />
      </Container>
    </div>
  );
}

export default Layout;
